index d0cfc39dc..b81f04ee6 100644
--- a/nginx/conf.d/wordpress.conf
+++ b/nginx/conf.d/wordpress.conf
@@ -92,6 +92,15 @@ server {
         return 404;
     }

+    # Uploads do blog principal: arquivo nao encontrado retorna 404 puro,
+    # nunca cai no PHP (evita WP renderizar archive.php "Arquivos" em URLs malformadas).
+    # ^~ tem prioridade sobre regex location ~* abaixo; multisite subsites
+    # (ex: /cultura/wp-content/uploads/) sao resolvidos pelas locations
+    # ^/[_0-9a-zA-Z-]+/(wp-content/.+)$ que reescrevem ANTES de chegar aqui.
+    location ^~ /wp-content/uploads/ {
+        try_files $uri =404;
+    }
+
     location ~* ^/(wp-config\.php|wp-config\.txt|readme\.html|license\.txt) {
         deny all;
     }
diff --git a/nginx/nginx.conf b/nginx/nginx.conf
index e6427fe6c..91d2bc0b9 100644
--- a/nginx/nginx.conf
+++ b/nginx/nginx.conf
@@ -35,7 +35,7 @@ http {
     # Configurações de buffer
     client_body_buffer_size 128K;
     client_header_buffer_size 4k;
-    client_max_body_size 64M;
+    client_max_body_size 100M;
     large_client_header_buffers 8 16k;

     # Configurações de timeout
@@ -67,6 +67,12 @@ http {
     # Resolver DNS do Docker (necessário para resolução dinâmica)
     resolver 127.0.0.11 valid=30s ipv6=off;

+    # WebP automático: sufixo .webp quando browser suporta (usado no try_files com fallback)
+    map $http_accept $webp_suffix {
+        default   "";
+        "~*image/webp" ".webp";
+    }
+
     # Incluir configurações dos sites
     include /etc/nginx/conf.d/*.conf;
 }
