1	<?php
2	/**
3	 * Deep Health Check — concertacaoamazonia.com.br
4	 * Verifica PHP-FPM (implícito — se chegou aqui, PHP está funcionando),
5	 * conexão com banco de dados Aurora e Redis ElastiCache.
6	 * Retorna 200 OK se tudo saudável, 503 Service Unavailable se qualquer check falhar.
7	 */
8	
9	header('Content-Type: application/json');
10	header('Cache-Control: no-cache, no-store, must-revalidate');
11	header('X-Robots-Tag: noindex');
12	
13	$checks = [];
14	$healthy = true;
15	
16	// PHP-FPM: implícito (este script está executando)
17	$checks['php_fpm'] = 'ok';
18	
19	// Banco de dados: tentar conexão via wp-config.php
20	try {
21	    // Carregar credenciais do WordPress sem inicializar o WP inteiro
22	    $wp_config = '/var/www/html/wp-config.php';
23	    if (!file_exists($wp_config)) {
24	        throw new Exception('wp-config.php not found');
25	    }
26	
27	    // Extrair credenciais sem dar define() conflitantes
28	    $config_content = file_get_contents($wp_config);
29	    preg_match("/define\s*\(\s*'DB_HOST'\s*,\s*'([^']+)'\s*\)/", $config_content, $host_match);
30	    preg_match("/define\s*\(\s*'DB_NAME'\s*,\s*'([^']+)'\s*\)/", $config_content, $name_match);
31	    preg_match("/define\s*\(\s*'DB_USER'\s*,\s*'([^']+)'\s*\)/", $config_content, $user_match);
32	    preg_match("/define\s*\(\s*'DB_PASSWORD'\s*,\s*'([^']+)'\s*\)/", $config_content, $pass_match);
33	
34	    if (!$host_match || !$name_match || !$user_match || !$pass_match) {
35	        throw new Exception('Could not parse DB credentials');
36	    }
37	
38	    $pdo = new PDO(
39	        "mysql:host={$host_match[1]};dbname={$name_match[1]};charset=utf8mb4",
40	        $user_match[1],
41	        $pass_match[1],
42	        [
43	            PDO::ATTR_TIMEOUT => 3,
44	            PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
45	        ]
46	    );
47	    $pdo->query('SELECT 1');
48	    $checks['database'] = 'ok';
49	    unset($pdo);
50	} catch (Exception $e) {
51	    $checks['database'] = 'error: ' . $e->getMessage();
52	    $healthy = false;
53	}
54	
55	// Redis: conectar via phpredis (extensao nativa) usando WP_REDIS_PATH e WP_REDIS_PASSWORD
56	try {
57	    $redis_socket = null;
58	    $redis_pass   = null;
59	
60	    if (isset($config_content)) {
61	        preg_match("/^\s*define\s*\(\s*'WP_REDIS_PATH'\s*,\s*'([^']+)'/m", $config_content, $sock_match);
62	        preg_match("/^\s*define\s*\(\s*'WP_REDIS_PASSWORD'\s*,\s*'([^']+)'/m", $config_content, $rpass_match);
63	        if (!empty($sock_match[1]))  $redis_socket = $sock_match[1];
64	        if (!empty($rpass_match[1])) $redis_pass   = $rpass_match[1];
65	    }
66	
67	    if (!class_exists('Redis')) {
68	        throw new Exception('phpredis extension not loaded');
69	    }
70	
71	    $r = new Redis();
72	    if ($redis_socket && file_exists($redis_socket)) {
73	        $r->connect($redis_socket, 0, 2.0);
74	    } else {
75	        $r->connect('127.0.0.1', 6379, 2.0);
76	    }
77	
78	    if ($redis_pass) {
79	        $r->auth($redis_pass);
80	    }
81	
82	    $pong = $r->ping('healthz');
83	    $r->close();
84	
85	    if ($pong === 'healthz' || $pong === true || $pong === '+PONG') {
86	        $checks['redis'] = 'ok';
87	    } else {
88	        throw new Exception('Unexpected PING response: ' . var_export($pong, true));
89	    }
90	} catch (Exception $e) {
91	    $checks['redis']      = 'error: ' . $e->getMessage();
92	    $checks['redis_note'] = 'degraded (non-fatal)';
93	}
94	
95	$status_code = $healthy ? 200 : 503;
96	http_response_code($status_code);
97	
98	echo json_encode([
99	    'status'  => $healthy ? 'healthy' : 'unhealthy',
100	    'checks'  => $checks,
101	    'time'    => date('c'),
102	], JSON_PRETTY_PRINT);
103

